// ╔══════════════════════════════════════════════════════════╗
// ║   TaskBarHero — Frida Hile Ayarları ve Kodları           ║
// ║   Yazar: Luxi & III7t                             ║
// ╚══════════════════════════════════════════════════════════╝

// ==============================================================================
// ⚙️ HİLE AYARLARI (İstediğiniz değerleri buradan değiştirebilirsiniz)
// ==============================================================================
const GODMODE      = true;      // true: Ölümsüzlük Açık  | false: Kapalı
const ONE_HIT_KILL = true;      // true: Tek Atma Açık   | false: Kapalı
const OHK_HASAR    = 9000.0;  // Düşmana verilecek hasar miktarı (Burayı arttırabilirsiniz!)

// ==============================================================================
// 🛠️ OYUN OFSETLERİ VE KODLARI (Yeni yama gelmedikçe dokunmayın)
// ==============================================================================
const OFF_IS_HERO     = 0x100;    // Unit->b_isHero (bool)
const OFF_ATTACKER    = 0x00;     // DamageInfo->Attacker (ptr)
const OFF_DAMAGE      = 0x08;     // DamageInfo->OriginDamage (float)
const RVA_TAKE_DAMAGE = 0xBFE930; // Unit.TakeDamage adresi (v2.5 yaması)

function banner() {
    console.log('\n\x1b[36m╔══════════════════════════════════════════════════╗\x1b[0m');
    console.log('\x1b[36m║   TaskBarHero Hook Script v2.5 • Pantheon     ║\x1b[0m');
    console.log('\x1b[36m║   Frida Sürümü: ' + Frida.version.padEnd(32) + ' ║\x1b[0m');
    console.log('\x1b[36m╠══════════════════════════════════════════════════╣\x1b[0m');
    console.log('║  Godmode      : ' + (GODMODE      ? '\x1b[32m✔ AÇIK \x1b[0m' : '\x1b[31m✘ KAPALI\x1b[0m') + '                        ║');
    console.log('║  One Hit Kill : ' + (ONE_HIT_KILL ? '\x1b[32m✔ AÇIK \x1b[0m' : '\x1b[31m✘ KAPALI\x1b[0m') + '  (' + String(OHK_HASAR).padEnd(10) + ' hasar)  ║');
    console.log('\x1b[36m╚══════════════════════════════════════════════════╝\x1b[0m\n');
}

banner();

const mod = Process.findModuleByName('GameAssembly.dll');
if (!mod) {
    console.log('[-] GameAssembly.dll bulunamadı — oyun açık mı?');
} else {
    console.log('[+] GameAssembly.dll @ ' + mod.base);

    try {
        Interceptor.attach(mod.base.add(RVA_TAKE_DAMAGE), {
            onEnter(args) {
                const unit   = args[0];
                const dmgInf = args[1];
                if (unit.isNull() || dmgInf.isNull()) return;

                try {
                    const heroAliyor  = unit.add(OFF_IS_HERO).readU8() !== 0;
                    const attackerPtr = dmgInf.add(OFF_ATTACKER).readPointer();
                    const heroVuruyor = !attackerPtr.isNull() && attackerPtr.add(OFF_IS_HERO).readU8() !== 0;

                    if (GODMODE && heroAliyor) {
                        dmgInf.add(OFF_DAMAGE).writeFloat(0);
                        console.log('[✔] Godmode — kahramana gelen hasar engellendi');
                    }

                    if (ONE_HIT_KILL && heroVuruyor && !heroAliyor) {
                        dmgInf.add(OFF_DAMAGE).writeFloat(OHK_HASAR);
                        console.log('[✔] One Hit Kill — düşmana ' + OHK_HASAR + ' hasar verildi');
                    }
                } catch (e) {
                    console.log('[-] Hook esnasında hata: ' + e.message);
                }
            }
        });
        console.log('[+] Hook başarıyla aktif edildi! İyi oyunlar!\n');
    } catch (err) {
        console.log('[-] Hook kurulamadı: ' + err.message);
    }
}
